class Solution:
    def lengthAfterTransformations(self, s: str, t: int, nums: List[int]) -> int:
        MOD = 10**9 + 7
        # Build 26x26 transition matrix M: M[i][j] = count of j produced from i in one step
        M = [[0] * 26 for _ in range(26)]
        for i in range(26):
            k = nums[i]
            for j in range(k):
                nxt = (i + 1 + j) % 26
                M[i][nxt] += 1

        # Matrix exponentiation: M^t
        def mat_mult(a, b):
            res = [[0] * 26 for _ in range(26)]
            for i in range(26):
                for k in range(26):
                    if a[i][k]:
                        for j in range(26):
                            res[i][j] = (res[i][j] + a[i][k] * b[k][j]) % MOD
            return res

        def mat_pow(mat, power):
            result = [[0] * 26 for _ in range(26)]
            for i in range(26):
                result[i][i] = 1  # Identity
            while power:
                if power & 1:
                    result = mat_mult(result, mat)
                mat = mat_mult(mat, mat)
                power >>= 1
            return result

        mat = mat_pow(M, t)

        # Count initial frequency
        freq = [0] * 26
        for ch in s:
            freq[ord(ch) - ord('a')] += 1

        # Compute final length
        length = 0
        for i in range(26):
            for j in range(26):
                length = (length + freq[i] * mat[i][j]) % MOD
        return length
